text:
&-handle {
  display: flex;
  justify-content: center;
  align-items: center;
  width: calc(var(--height) - 2 * var(--border-width));
  height: calc(var(--height) - 2 * var(--border-width));
  border-radius: calc(var(--height) - 2 * var(--border-width));
  background: var(--adm-color-text-light-solid);
  position: absolute;
  z-index: 2;
  top: var(--border-width);
  left: var(--border-width);
  transition: all 200ms;
  box-shadow: 0 0 2px 0 rgba(0, 0, 0, 0.2), 0 2px 11.5px 0 rgba(0, 0, 0, 0.08),
    -1px 2px 2px 0 rgba(0, 0, 0, 0.1);
}

h1, .h1,
    h2, .h2,
    h3, .h3,
    h4, .h4,
    h5, .h5,
    h6, .h6,
    .heading {
        color: var(--headings-color);
        font-family: var(--headings-font-family, var(--base-font-family));
        font-size: var(--headings-font-size);
        font-weight: var(--headings-font-weight);
        line-height: var(--headings-line-height);
        letter-spacing: var(--headings-letter-spacing);
        text-transform: var(--headings-text-transform);
    }

@keyframes stroke-dash-loop {
  0% {
    stroke-dasharray: var(--tv-motion-stroke-dasharray-0, 1, 200);
    stroke-dashoffset: var(--tv-motion-stroke-offset-0, 0);
  }
  50% {
    stroke-dasharray: var(--tv-motion-stroke-dasharray-50, 90, 150);
    stroke-dashoffset: var(--tv-motion-stroke-offset-50, -40px);
  }
  100% {
    stroke-dasharray: var(--tv-motion-stroke-dasharray-100, 90, 150);
    stroke-dashoffset: var(--tv-motion-stroke-offset-100, -120px);
  }
}

@keyframes stroke-dash-reverse {
  0% {
    stroke-dasharray: var(--tv-motion-stroke-dasharray-0, 1, 200);
    stroke-dashoffset: var(--tv-motion-stroke-offset-0, 0);
  }
  50% {
    stroke-dasharray: var(--tv-motion-stroke-dasharray-50, 90, 150);
    stroke-dashoffset: var(--tv-motion-stroke-offset-reverse-50, 40px);
  }
  100% {
    stroke-dasharray: var(--tv-motion-stroke-dasharray-100, 90, 150);
    stroke-dashoffset: var(--tv-motion-stroke-offset-reverse-100, 120px);
  }
}

@keyframes enlarge-in-fade {
  0% {
    transform: scale(var(--tv-motion-scale-start, 0));
    opacity: var(--tv-motion-scale-opacity-start, 0);
  }
  50% {
    transform: scale(var(--tv-motion-scale-mid, 0.5));
    opacity: var(--tv-motion-scale-opacity-mid, 0.5);
  }
  100% {
    transform: scale(var(--tv-motion-scale-end, 1));
    opacity: var(--tv-motion-scale-opacity-end, 1);
  }
}

@keyframes shrink-out-fade {
  0% {
    transform: scale(var(--tv-motion-scale-end, 1));
    opacity: var(--tv-motion-scale-opacity-end, 1);
  }
  50% {
    transform: scale(var(--tv-motion-scale-mid, 0.5));
    opacity: var(--tv-motion-scale-opacity-mid, 0.5);
  }
  100% {
    transform: scale(var(--tv-motion-scale-start, 0));
    opacity: var(--tv-motion-scale-opacity-start, 0);
  }
}

&--out {
  flex-direction: row-reverse;

  .AvocadoMessages-skeleton-line {
    background: linear-gradient(
      90deg,
      color-mix(in srgb, var(--primary-color) 25%, var(--avmsg-sk-base)) 25%,
      color-mix(in srgb, var(--primary-color) 15%, var(--avmsg-sk-shine)) 50%,
      color-mix(in srgb, var(--primary-color) 25%, var(--avmsg-sk-base)) 75%
    );
    background-size: 800px 100%;
    animation: avmsg-shimmer 1.4s infinite linear;
  }
}

&::after {
  content: "";
  background-color: var(--weui-BG-2);
  width: ~"calc(var(--weui-STEPS-DOT-SIZE) +  2 * var(--weui-STEPS-HORIZONAL-DOT-GAP))";
  height: ~"calc(var(--weui-STEPS-DOT-SIZE) +  2 * var(--weui-STEPS-HORIZONAL-DOT-GAP))";
  position: absolute;
  top: 0;
  left: 0;
  transform: translate(~"calc(-50% + var(--weui-STEPS-DOT-SIZE) / 2)", -50%);
}

&.is-visible .primary-nav__item {
	.transition( all 240ms cubic-bezier(0.645, 0.045, 0.355, 1) );
	.translate3d(0, 0, 0);
	opacity: 1;

	&:nth-child(1) { .transition-delay(100ms); }
	&:nth-child(2) { .transition-delay(200ms); }
	&:nth-child(3) { .transition-delay(300ms); }
	&:nth-child(4) { .transition-delay(400ms); }
	&:nth-child(5) { .transition-delay(500ms); }
	&:nth-child(6) { .transition-delay(600ms); }
	&:nth-child(7) { .transition-delay(700ms); }
}

&__node {
  position: absolute;
  top: 2px;
  left: 2px;
  width: var(--van-switch-node-size);
  height: var(--van-switch-node-size);
  // https://github.com/vant-ui/vant/issues/9839
  font-size: inherit;
  background: var(--van-switch-node-background);
  border-radius: 100%;
  box-shadow: var(--van-switch-node-shadow);
  transition: transform var(--van-switch-duration)
    cubic-bezier(0.3, 1.05, 0.4, 1.05);
}

& .Search-input {
	& when (lightness(@header-bg) <= 50%) {
		--fluent-temp-input-text-color: ~"#ffffffc8";
		&:active, &:focus-within {
			--fluent-temp-input-text-color: white;
		}
	}
	& when (lightness(@header-bg) > 50%) {
		--fluent-temp-input-text-color: ~"#000000a8";
		&:active, &:focus-within {
			--fluent-temp-input-text-color: black;
		}
	}
}

&-title {
  position: relative;
  padding: @v-spacing-large 0;
  padding: var(--am-collapse-title-paddingTB, @v-spacing-large) 0;
  margin: 0 @h-spacing-large;
  margin: 0 var(--am-collapse-title-marginLR, @h-spacing-large);
  .hairline('bottom');
  &-arrow {
    font-size: @icon-size-xs;
    font-size: var(--am-collapse-arrow-size, @icon-size-xs);
    color: @color-text-weak;
    color: var(--am-collapse-arrow-color, @color-text-weak);
  }
}

&-vertical {
  flex-direction: column;
  padding: @v-spacing-large 0;
  padding: var(--am-input-vlabel-paddingTB, @v-spacing-large) 0;
  .am-input-label {
    align-self: flex-start;
    font-size: @font-size-subtitle;
    font-size: var(--am-input-vlabel-font-size, @font-size-subtitle);
    color: @color-text-subtitle;
    color: var(--am-input-vlabel-color, @color-text-subtitle);
  }
  .a-input-placeholder {
    margin-left: -3px;
  }
}

&-option {
  display: flex;
  flex: 0 0 @size-6;
  flex: 0 0 var(--am-stepper-btn-size, @size-6);
  height: @size-6;
  height: var(--am-stepper-btn-size, @size-6);
  justify-content: center;
  align-items: center;
  border: @border-width-standard solid @color-divider-line;
  border: var(--am-stepper-borderWidth, @border-width-standard) solid var(--am-stepper-borderColor, @color-divider-line);
  border-radius: @corner-radius-sm;
  border-radius: var(--am-stepper-borderRadius, @corner-radius-sm);
  box-sizing: border-box;
}

&-clear {
  display: flex;
  align-items: center;
  position: relative;
  visibility: hidden;
  width: @size-7;
  width: var(--am-search-icon-area, @size-7);
  height: @size-7;
  height: var(--am-search-icon-area, @size-7);
  &-font {
    font-size: @font-size-subtitle;
    font-size: var(--am-search-iconsize, @font-size-subtitle);
    color: @color-text-weak;
    color: var(--am-search-clearicon-color, @color-text-weak);
  }
}

&-voice {
  display: flex;
  align-items: center;
  position: relative;
  width: @size-7;
  width: var(--am-search-icon-area, @size-7);
  height: @size-7;
  height: var(--am-search-icon-area, @size-7);
  &-font {
    font-size: @font-size-subtitle;
    font-size: var(--am-search-iconsize, @font-size-subtitle);
    color: @color-text-subtitle;
    color: var(--am-search-vocieicon-color, @color-text-subtitle);
  }
}

&-title {
  margin: @size-5 auto 0;
  margin: var(--am-result-margin-vertical, @size-5) auto 0;
  max-width: calc(100vw - @size-12);
  max-width: calc(100vw - var(--am-result-title-h-spacing, @size-12));
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  text-align: center;
  font-size: @font-size-title;
  font-size: var(--am-result-title-fontSize, @font-size-title);
  color: @color-text-title;
  color: var(--am-result-title-color, @color-text-title);
}

&-option {
  flex: 1;
  text-align: right;
  align-self: center;
  &__arrow {
    margin-left: @size-1/2;
    margin-top: @size-1;
    vertical-align: -@size-1/2;
    font-size: @font-size-subtitle;
    font-size: var(--am-coupon-detail-arrow-size, @font-size-subtitle);
    color: @color-text-weak;
    color: var(--am-coupon-detail-arrow-color, @color-text-weak);
  }
}

@supports (backdrop-filter: blur(1px)) or (-webkit-backdrop-filter: blur(1px)) {
    .v-backdrop-blurs {
        -webkit-backdrop-filter: blur(10px);
        backdrop-filter: blur(10px);
    }

    #write .v-post-card.v-backdrop-blurs {
        background: var(--pn08);
    }

    .v-caption.full.v-backdrop-blurs {
        background: radial-gradient(rgba(var(--df-r-lg), var(--df-g-lg), var(--df-b-lg),1) 50%,
            rgba(var(--df-r-lg), var(--df-g-lg), var(--df-b-lg),.9));
    }
}

&__line {
  width: 1px;
  height: @font-size-subcontent;
  height: var(--am-footer-link-lineSize, @font-size-subcontent);
  overflow: hidden;
  margin: 0 @h-spacing-large @v-spacing-standard;
  margin: 0 var(--am-footer-link-lineMarginLR, @h-spacing-large) var(--am-footer-link-lineMarginB, @v-spacing-standard);
  font-size: 0;
  background-color: @color-divider-line;
  background-color: var(--am-footer-link-lineColor, @color-divider-line);
}

&-desc {
	height: @font-size-list;
	height: var(--am-grid-desc-height, @font-size-list);
	overflow: hidden;
	text-overflow: ellipsis;
	display: -webkit-box;
   -webkit-line-clamp: 1;
   -webkit-box-orient: vertical;
	word-break: break-all;
	line-height: @font-size-list;
	line-height: var(--am-grid-desc-height, @font-size-list);
	font-size: @font-size-subcontent;
	font-size: var(--am-grid-desc-fontSize, @font-size-subcontent);
	color: @color-text-subtitle;
	color: var(--am-grid-desc-color, @color-text-subtitle);
}

&-clear {
  display: flex;
  height: @icon-size-sm;
  height: var(--am-input-icon-size, @icon-size-sm);
  width: @icon-size-sm;
  width: var(--am-input-icon-size, @icon-size-sm);
  justify-content: center;
  align-items: center;
  &-icon {
    line-height: @line-height-base;
    line-height: var(--am-input-icon-line-height, @line-height-base);
  }
}

&[overlay] {
  --bg-color: rgba(@base, var(--overlay-opacity));
  --bg-color-highlight: rgba(
    @base,
    max(0.4, calc(var(--overlay-opacity) * 1.2))
  );
  --text-shadow:
    -1px -1px 0px @base, 0px -1px 0px @base, 1px -1px 0px @base, -1px 0px
    0px @base, 1px 0px 0px @base, -1px 1px 0px @base, 0px 1px 0px @base,
    1px 1px 0px @base;
  --text-color: @text;
}

span {
    &.ui-icon-gear, &.ui-icon-plusthick, &.ui-icon-star, &.ui-icon-minus, &.ui-icon-closethick, &.ui-icon-help, &.ui-icon-newwin,
    &.ui-icon-minusthick, &.ui-icon-extlink, &.ui-icon-close, &.icon-cancel, &.ui-icon-arrowthick-1-w, &.ui-icon-arrowthick-1-e, &.ui-icon-plus  {
        &:before {
            font-size: @font-awesome-icon-size + 1;
        }
    }
    &.ui-icon.fa-2x:before {
        font-weight: @font-awesome-icon2x-size + 1;
    }
}

@gray-base:              #000;
@gray-darker:            lighten(@gray-base, 13.5%); // #222
@gray-dark:              lighten(@gray-base, 20%);   // #333
@gray:                   lighten(@gray-base, 33.5%); // #555
@gray-light:             lighten(@gray-base, 46.7%); // #777
@gray-lighter:           lighten(@gray-base, 93.5%); // #eee

@brand-primary:         darken(#428bca, 6.5%); // #337ab7
@brand-success:         #5cb85c;
@brand-info:            #5bc0de;
@brand-warning:         #f0ad4e;
@brand-danger:          #d9534f;

@state-success-text:             #3c763d;
@state-success-bg:               #dff0d8;
@state-success-border:           darken(spin(@state-success-bg, -10), 5%);

@state-info-text:                #31708f;
@state-info-bg:                  #d9edf7;
@state-info-border:              darken(spin(@state-info-bg, -10), 7%);

@state-warning-text:             #8a6d3b;
@state-warning-bg:               #fcf8e3;
@state-warning-border:           darken(spin(@state-warning-bg, -10), 5%);

@state-danger-text:              #a94442;
@state-danger-bg:                #f2dede;
@state-danger-border:            darken(spin(@state-danger-bg, -10), 5%);

body .ui-panelgrid {

    .ui-panelgrid-content.ui-grid, .ui-grid-responsive .ui-grid-row, .ui-panelgrid-header {
        border: 0;
    }

    &.card {
        box-shadow: 0 1px 3px 0 rgba(0, 0, 0, 0.2), 0 1px 1px 0 rgba(0, 0, 0, 0.14), 0 2px 1px -1px rgba(0, 0, 0, 0.12);
        -webkit-box-shadow: 0 1px 3px 0 rgba(0, 0, 0, 0.2), 0 1px 1px 0 rgba(0, 0, 0, 0.14), 0 2px 1px -1px rgba(0, 0, 0, 0.12);
        -moz-box-shadow: 0 1px 3px 0 rgba(0, 0, 0, 0.2), 0 1px 1px 0 rgba(0, 0, 0, 0.14), 0 2px 1px -1px rgba(0, 0, 0, 0.12);
        border: none;
    }
}

// Shadow
@shadow-color           : rgba(0, 0, 0, .2);
@shadow-base            : @shadow-down;
@shadow-card            : 0 1px 1px 0 rgba(0,0,0,.1);
@shadow-up              : 0 -1px 6px @shadow-color;
@shadow-down            : 0 1px 6px @shadow-color;
@shadow-left            : -1px 0 6px @shadow-color;
@shadow-right           : 1px 0 6px @shadow-color;

@media (max-width: @screen-xs) {
    span {
        &.ui-icon-gear, &.ui-icon-plusthick, &.ui-icon-star, &.ui-icon-minus, &.ui-icon-closethick, &.ui-icon-help, &.ui-icon-newwin,
        &.ui-icon-minusthick, &.ui-icon-extlink, &.ui-icon-close, &.icon-cancel, &.ui-icon-arrowthick-1-w, &.ui-icon-arrowthick-1-e, &.ui-icon-plus  {
            &:before {
                font-size: @font-awesome-icon-size + 1;
            }
        }
        &.ui-icon.fa-2x:before {
            font-weight: @font-awesome-icon2x-size + 1;
        }
    }
}

path,
    .DeeplLogoText-module--logoText--34a4f,
    .ProBanner2021-module--lockitem--febe3,
    .FlyoutMenuButton-module--flyoutMenuButton--97ae6::after,
    #top-navi-sidemenu-opener,
    .pageFooterV2-module--socialMediaLinks--71305,
    .ProBanner2021-module--checkitem--2d8e7,
    [src*="https://static.deepl.com/img/app_desktop.svg"] {
      filter: @text-filter;
    }
